      "path": "src/modules/members/routes.js",
      "content": "const express = require('express');
const router = express.Router();
const membersService = require('../members/service');
const { sendError } = require('../../lib/errors');

router.post('/', (req, res) => {
  const { userId, role } = req.body;

  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_BODY', 'Body must contain userId and role');
  }

  const member = membersService.createMember(req.projectId, userId, role);

  if (member.error) {
    return sendError(res, member.status, member.code, member.message);
  }

  res.status(201).json({ member });
});

module.exports = router;
