      "content": "const express = require('express');
const router = express.Router();
const projectsService = require('../projects/service');
const { sendError } = require('../../lib/errors');

router.post('/', (req, res) => {
  const { name } = req.body;

  if (!name) {
    return sendError(res, 400, 'INVALID_BODY', 'Body must contain name');
  }

  const project = projectsService.createProject(name);

  res.status(201).json({ project });
});

router.get('/:projectId', (req, res) => {
  const project = projectsService.getProject(req.params.projectId);

  if (!project) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }

  res.json({ project });
});

module.exports = router;
